INSERT INTO glossary_terms (term, slug, definition, example, category, related_terms) VALUES
('Frontend', 'frontend', 'The part of a web application that runs in the user browser and handles the user interface.', 'React, Vue, Angular, HTML, CSS, JavaScript', 'Development', 'Backend,Full Stack,API'),
('Backend', 'backend', 'The server-side part of an application that handles data storage, business logic, and API endpoints.', 'Spring Boot, Node.js, Django, FastAPI', 'Development', 'Frontend,Full Stack,Database'),
('Full Stack', 'full-stack', 'A web application that includes both frontend (client-side) and backend (server-side) components working together.', 'A React frontend + Spring Boot backend + PostgreSQL database', 'Development', 'Frontend,Backend,API'),
('Repository', 'repository', 'A storage location for your code that tracks all changes over time using version control.', 'A Git repository on GitHub containing your project files', 'Git', 'Git,GitHub,Branch,Commit'),
('Git', 'git', 'A distributed version control system that tracks changes in source code during software development.', 'git init, git add, git commit, git push', 'Git', 'Repository,GitHub,Branch,Commit'),
('GitHub', 'github', 'A web-based platform for hosting Git repositories, collaborating on code, and managing projects.', 'Creating a repository at github.com/yourname/project', 'Git', 'Git,Repository,Pull Request,CI/CD'),
('Branch', 'branch', 'A parallel version of your codebase that allows you to work on features independently without affecting the main code.', 'git switch -c feature/login creates a new branch for login work', 'Git', 'Git,Merge,Commit,Pull Request'),
('Commit', 'commit', 'A snapshot of your code at a specific point in time, saved to the repository history.', 'git commit -m "Add user authentication"', 'Git', 'Git,Branch,Push,Repository'),
('Push', 'push', 'Upload your local commits to a remote repository like GitHub.', 'git push origin main sends your commits to GitHub', 'Git', 'Git,Pull,Commit,Remote'),
('Pull', 'pull', 'Download changes from a remote repository and merge them into your local branch.', 'git pull origin main fetches and merges the latest changes', 'Git', 'Git,Push,Fetch,Merge'),
('Merge', 'merge', 'Combine changes from one branch into another, integrating different lines of development.', 'Merging a feature branch into the main branch after review', 'Git', 'Git,Branch,Pull Request,Conflict'),
('Clone', 'clone', 'Create a local copy of a remote repository on your machine.', 'git clone https://github.com/user/repo.git', 'Git', 'Git,Repository,Remote'),
('Build', 'build', 'The process of compiling and packaging your source code into a runnable application.', 'npm run build creates a production bundle of a React app', 'Development', 'Deploy,CI/CD,Compilation'),
('Deploy', 'deploy', 'The process of releasing your application to a production environment where users can access it.', 'Deploying a React app to Netlify or a Spring Boot app to Render', 'Deployment', 'Build,Hosting,Production,CI/CD'),
('Hosting', 'hosting', 'A service that stores your application files and serves them to users over the internet.', 'Netlify for frontend, Render for backend, AWS for both', 'Deployment', 'Deploy,Server,Domain,CDN'),
('Server', 'server', 'A computer or program that provides functionality to other computers (clients) over a network.', 'A Spring Boot application running on Render that handles API requests', 'Infrastructure', 'Backend,Hosting,API,Database'),
('Database', 'database', 'An organized collection of structured data that can be accessed, managed, and updated.', 'PostgreSQL storing user accounts, posts, and comments', 'Infrastructure', 'Backend,SQL,Supabase,Query'),
('API', 'api', 'Application Programming Interface - a set of rules that allows different software applications to communicate.', 'A REST API endpoint like GET /api/users that returns a list of users', 'Development', 'Backend,Endpoint,JSON,HTTP'),
('API Key', 'api-key', 'A unique identifier used to authenticate requests to an API service.', 'Using a Gemini API key to authenticate AI requests from your backend', 'Security', 'API,Secret,Authentication'),
('Secret', 'secret', 'Sensitive information such as passwords, API keys, or tokens that must be protected from unauthorized access.', 'Database passwords, JWT signing keys, service account credentials', 'Security', 'API Key,Environment Variable,Encryption'),
('Environment Variable', 'environment-variable', 'A dynamic value that can affect how running processes behave, used to configure applications without code changes.', 'DATABASE_URL=https://db.example.com, JWT_SECRET=abc123', 'Deployment', 'Secret,Configuration,.env'),
('Production', 'production', 'The live environment where your application runs and is accessed by real users.', 'Your app deployed at https://myapp.com that customers use', 'Deployment', 'Development,Staging,Deploy'),
('Development', 'development', 'The local environment where you write and test code before deploying.', 'Running your app on localhost:5173 or localhost:8080', 'Deployment', 'Production,Staging,Localhost'),
('Staging', 'staging', 'A pre-production environment that mirrors production for final testing before release.', 'A deployment at https://staging.myapp.com for QA testing', 'Deployment', 'Production,Development,Testing'),
('Domain', 'domain', 'A human-readable address that maps to an IP address where your application is hosted.', 'myapp.com, deploypilot.io, example.org', 'Infrastructure', 'DNS,Hosting,HTTPS,URL'),
('DNS', 'dns', 'Domain Name System - translates human-readable domain names into IP addresses.', 'myapp.com -> 192.0.2.1', 'Infrastructure', 'Domain,URL,IP Address'),
('HTTPS', 'https', 'HyperText Transfer Protocol Secure - encrypted communication between browser and server.', 'The lock icon in your browser when visiting a secure website', 'Security', 'SSL,TLS,Security,Certificate'),
('SSL', 'ssl', 'Secure Sockets Layer - encryption protocol for secure internet communication (now superseded by TLS).', 'An SSL certificate installed on your server to enable HTTPS', 'Security', 'HTTPS,TLS,Certificate,Security'),
('CORS', 'cors', 'Cross-Origin Resource Sharing - a security mechanism that controls which domains can access your API.', 'Configuring your Spring Boot backend to allow requests only from your Netlify frontend', 'Security', 'API,Security,HTTP Header,Origin'),
('Authentication', 'authentication', 'The process of verifying who a user is, typically through passwords, tokens, or OAuth.', 'Logging in with username and password to receive a JWT token', 'Security', 'Authorization,JWT,OAuth,Login'),
('Authorisation', 'authorisation', 'The process of determining what an authenticated user is allowed to do.', 'Checking if the logged-in user owns a project before allowing deletion', 'Security', 'Authentication,Permission,Role,Access Control'),
('JWT', 'jwt', 'JSON Web Token - a compact, self-contained way to transmit information between parties as a JSON object.', 'A token containing user ID and role, signed with a secret key', 'Security', 'Authentication,Authorization,Token,Secret'),
('CI/CD', 'ci-cd', 'Continuous Integration / Continuous Deployment - automated building, testing, and deployment of code.', 'GitHub Actions that run tests on push and deploy to Render automatically', 'Deployment', 'GitHub Actions,Automation,Testing,Deploy'),
('Docker', 'docker', 'A platform for developing, shipping, and running applications in lightweight containers.', 'A Dockerfile that packages your Spring Boot app with Java runtime', 'Infrastructure', 'Container,Image,Docker Compose,Deployment'),
('Migration', 'migration', 'A controlled way to make incremental, reversible changes to a database schema.', 'Flyway script V1__create_users_table.sql that creates the users table', 'Database', 'Database,Schema,Version Control,Flyway'),
('Webhook', 'webhook', 'An automated message sent from one app to another when a specific event occurs.', 'GitHub sending a notification to Netlify when code is pushed to trigger redeployment', 'Integration', 'API,Event,Automation,Trigger'),
('Serverless', 'serverless', 'A cloud computing model where the provider manages servers and automatically scales resources.', 'AWS Lambda or Firebase Functions that run code without managing servers', 'Infrastructure', 'Cloud,Function,Scaling,API'),
('PWA', 'pwa', 'Progressive Web App - a web application that uses modern browser features to provide a native app-like experience.', 'A React app that works offline, can be installed on mobile, and receives push notifications', 'Frontend', 'Service Worker,Offline,Mobile,Web App');
